from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    # Group triples by subject
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Find the primary subject (likely an airport)
    airports = [s for s in subject_map.keys() if any(p in ["cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel", "elevationAboveTheSeaLevelInFeet", "elevationAboveTheSeaLevelInMetres", "icaoLocationIdentifier", "iataLocationIdentifier", "locationIdentifier", "operatingOrganisation", "owner"] for p, _ in subject_map[s])]
    primary_subject = airports[0] if airports else list(subject_map.keys())[0]

    # Build a complex sentence by connecting related entities
    sentence = f"{primary_subject} "

    # Extract key information for complex sentence construction
    city_served = None
    location = None
    country = None
    capital = None
    elevation = None
    runway_info = []
    other_info = []

    for predicate, obj in subject_map[primary_subject]:
        if predicate == "cityServed":
            city_served = obj
        elif predicate == "location":
            location = obj
        elif predicate == "country":
            country = obj
        elif predicate == "capital":
            capital = obj
        elif predicate == "elevationAboveTheSeaLevel":
            elevation = f"{obj} metres above sea level"
        elif predicate == "elevationAboveTheSeaLevelInFeet":
            elevation = f"{obj} feet above sea level"
        elif predicate == "elevationAboveTheSeaLevelInMetres":
            elevation = f"{obj} metres above sea level"
        elif predicate == "runwayLength":
            runway_info.append(f"runway of {obj} metres")
        elif predicate == "runwayName":
            runway_info.append(f"runway named {obj}")
        elif predicate == "1stRunwayLengthFeet":
            runway_info.append(f"first runway of {obj} feet")
        elif predicate == "1stRunwaySurfaceType":
            runway_info.append(f"first runway with {obj} surface")
        elif predicate == "3rdRunwayLengthFeet":
            runway_info.append(f"third runway of {obj} feet")
        elif predicate == "3rdRunwaySurfaceType":
            runway_info.append(f"third runway with {obj} surface")
        elif predicate == "runwaySurfaceType":
            runway_info.append(f"runway surface type of {obj}")
        elif predicate == "icaoLocationIdentifier":
            other_info.append(f"ICAO identifier {obj}")
        elif predicate == "iataLocationIdentifier":
            other_info.append(f"IATA identifier {obj}")
        elif predicate == "locationIdentifier":
            other_info.append(f"location identifier {obj}")
        elif predicate == "operatingOrganisation":
            other_info.append(f"operated by {obj}")
        elif predicate == "owner":
            other_info.append(f"owned by {obj}")
        elif predicate == "nativeName":
            other_info.append(f"also known as {obj}")

    # Build complex sentence structure
    clauses = []

    # City served clause
    if city_served:
        clauses.append(f"serves the city of {city_served}")

    # Location clause
    if location:
        clauses.append(f"is located in {location}")

    # Country clause
    if country and not (city_served and country in city_served):
        clauses.append(f"in {country}")

    # Capital clause (if country is mentioned, connect capital)
    if capital and country:
        clauses.append(f"of which the capital is {capital}")
    elif capital:
        clauses.append(f"has {capital} as its capital")

    # Elevation clause
    if elevation:
        clauses.append(f"with an elevation of {elevation}")

    # Runway clauses
    if runway_info:
        runway_desc = " with " + " and ".join(runway_info)
        clauses.append(runway_desc)

    # Other info
    if other_info:
        clauses.append(f"with {', '.join(other_info)}")

    # Connect clauses with appropriate conjunctions
    if len(clauses) > 1:
        sentence += ", ".join(clauses[:-1]) + ", and " + clauses[-1]
    elif len(clauses) == 1:
        sentence += ", " + clauses[0]
    else:
        sentence += "."

    return sentence + "."

